Finding the rotation needed for a turret to track a target actor:

```cpp
#include <cmath>

struct FVector2D {
    float X, Y;
};

float GetAngleToTarget(FVector2D TurretPos, FVector2D TargetPos) {
    float DeltaX = TargetPos.X - TurretPos.X;
    float DeltaY = TargetPos.Y - TurretPos.Y;

    // atan2 handles signs and avoids division by zero errors
    float AngleRadians = std::atan2(DeltaY, DeltaX);

    // Convert to degrees for editor use
    return AngleRadians * (180.0f / 3.14159265f);
}
```
